class OrdersRepository extends BaseRepository {
  constructor(db) {
    super(db, 'orders', ['user_id', 'status', 'total_amount', 'created_at', 'updated_at']);
  }

  async createWithItems(orderData, items) {
    return this.db.transaction(async (tx) => {
      const orderResult = await tx.query(
        'INSERT INTO orders (user_id, status, total_amount) VALUES ($1, $2, $3) RETURNING *',
        [orderData.user_id, orderData.status || 'pending', orderData.total_amount || 0]
      );
      const order = orderResult.rows[0];

      const createdItems = [];
      for (const item of items) {
        const itemResult = await tx.query(
          'INSERT INTO order_items (order_id, product_id, quantity, unit_price) VALUES ($1, $2, $3, $4) RETURNING *',
          [order.id, item.product_id, item.quantity, item.unit_price]
        );
        createdItems.push(itemResult.rows[0]);
      }

      return { order, items: createdItems };
    });
  }
}

